  width: 16px;
  height: 16px;
  flex-shrink: 0;
  color: var(--icon-secondary);
}

/* Action buttons row — BTButton handles its own styles */
.bt-input-rich-editor__link-actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--space-sm);
}

/* ── Quill 2.x list & alignment (extracted from quill.core.css v2.0.3) ─── */
/*
 * theme:false skips loading quill.core.css, so list markers and alignment
 * classes never render without these rules. Scoped to our editor wrapper.
 */

/* Counter reset on editor root */
.bt-input-rich-editor__editor .ql-editor {
  counter-reset: list-0 list-1 list-2 list-3 list-4 list-5 list-6 list-7 list-8 list-9;
}

/* Reset list counters between paragraphs/headings */
@supports (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor p,
  .bt-input-rich-editor__editor .ql-editor h1,
  .bt-input-rich-editor__editor .ql-editor h2,
  .bt-input-rich-editor__editor .ql-editor h3 {
    counter-set: list-0 list-1 list-2 list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}
@supports not (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor p,
  .bt-input-rich-editor__editor .ql-editor h1,
  .bt-input-rich-editor__editor .ql-editor h2,
  .bt-input-rich-editor__editor .ql-editor h3 {
    counter-reset: list-0 list-1 list-2 list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}

/* List item base */
.bt-input-rich-editor__editor .ql-editor li {
  list-style-type: none;
  padding-inline-start: 1.5em;
  position: relative;
}

/* Quill 2.x places the marker in a .ql-ui span (position:absolute) */
.bt-input-rich-editor__editor .ql-editor .ql-ui {
  position: absolute;
}

.bt-input-rich-editor__editor .ql-editor li > .ql-ui::before {
  display: inline-block;
  margin-inline-start: -1.5em;
  margin-inline-end: 0.3em;
  text-align: end;
  white-space: nowrap;
  width: 1.2em;
}

/* Bullet */
.bt-input-rich-editor__editor .ql-editor li[data-list=bullet] > .ql-ui::before {
  content: '\2022';
}

/* Reset nested counters per list item */
@supports (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor li[data-list] {
    counter-set: list-1 list-2 list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}
@supports not (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor li[data-list] {
    counter-reset: list-1 list-2 list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}

/* Ordered list — level 0 */
.bt-input-rich-editor__editor .ql-editor li[data-list=ordered] {
  counter-increment: list-0;
}
.bt-input-rich-editor__editor .ql-editor li[data-list=ordered] > .ql-ui::before {
  content: counter(list-0, decimal) '. ';
}

/* Ordered list — level 1 (indent-1) */
.bt-input-rich-editor__editor .ql-editor li[data-list=ordered].ql-indent-1 {
  counter-increment: list-1;
}
.bt-input-rich-editor__editor .ql-editor li[data-list=ordered].ql-indent-1 > .ql-ui::before {
  content: counter(list-1, lower-alpha) '. ';
}
@supports (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor li[data-list].ql-indent-1 {
    counter-set: list-2 list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}
@supports not (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor li[data-list].ql-indent-1 {
    counter-reset: list-2 list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}

/* Ordered list — level 2 (indent-2) */
.bt-input-rich-editor__editor .ql-editor li[data-list=ordered].ql-indent-2 {
  counter-increment: list-2;
}
.bt-input-rich-editor__editor .ql-editor li[data-list=ordered].ql-indent-2 > .ql-ui::before {
  content: counter(list-2, lower-roman) '. ';
}
@supports (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor li[data-list].ql-indent-2 {
    counter-set: list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}
@supports not (counter-set: none) {
  .bt-input-rich-editor__editor .ql-editor li[data-list].ql-indent-2 {
    counter-reset: list-3 list-4 list-5 list-6 list-7 list-8 list-9;
  }
}

/* Indent padding (levels 1-3) */
.bt-input-rich-editor__editor .ql-editor .ql-indent-1:not(.ql-direction-rtl)   { padding-left: 3em; }
.bt-input-rich-editor__editor .ql-editor li.ql-indent-1:not(.ql-direction-rtl) { padding-left: 4.5em; }
.bt-input-rich-editor__editor .ql-editor .ql-indent-2:not(.ql-direction-rtl)   { padding-left: 6em; }
.bt-input-rich-editor__editor .ql-editor li.ql-indent-2:not(.ql-direction-rtl) { padding-left: 7.5em; }
.bt-input-rich-editor__editor .ql-editor .ql-indent-3:not(.ql-direction-rtl)   { padding-left: 9em; }
.bt-input-rich-editor__editor .ql-editor li.ql-indent-3:not(.ql-direction-rtl) { padding-left: 10.5em; }

/* Alignment classes */
.bt-input-rich-editor__editor .ql-editor .ql-align-center  { text-align: center; }
.bt-input-rich-editor__editor .ql-editor .ql-align-right   { text-align: right; }
.bt-input-rich-editor__editor .ql-editor .ql-align-justify { text-align: justify; }

/* Images inserted via toolbar */
.bt-input-rich-editor__editor .ql-editor img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* Links */
.bt-input-rich-editor__editor .ql-editor a {
