/*
 * BTInputWithLabel — text input with static label pill(s) on left, right, or both.
 *
 * Shared by Vue (BTInputWithLabel.vue) and React (BTInputWithLabel.tsx).
 *
 * Figma node 368-6832.
 *
 * Layout (flex-row, height 48 px):
 * ┌── field ──────────────────────────────────────────────────────────┐
 * │ [left-pill?] │  label (14 px resting → 12 px float)  [×?] │ [right?] │
 * │              │  input text (always 100 % of content area)  │          │
 * └───────────────────────────────────────────────────────────────────┘
 *
 * Height arithmetic (box-sizing: border-box everywhere):
 *   Field container: 48 px  →  inner: 46 px (1 px border each side)
 *   Content area (align-self: stretch, border-box): 46 px outer
 *     Resting:  no padding   →  inner 46 px; input height 46 px, text centred by browser
 *     Floating: pad 8/8      →  inner 30 px; input height 30 px, padding-top 16 px
 *       → label at outer-top + 8 px (in pad zone), input text at 8 + 16 = 24 px ✓
 *
 * Key rules:
 *   • `box-sizing: border-box` on content area is mandatory — without it, padding
 *     increases the outer height beyond 46 px and the field grows.
 *   • Input uses `height: 100%` so it always fills the content area's inner height.
 *   • Clear (×) is a SIBLING of the content area (not inside it) so it can use
 *     `align-self: center` independent of the content padding.
 */

/* ── Outer wrapper ─────────────────────────────────────────────── */
.bt-input-with-label__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Field container ───────────────────────────────────────────── */
.bt-input-with-label {
  display: flex;
  flex-direction: row;
  align-items: stretch;                    /* pills + content fill full height */
  height: 48px;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  box-sizing: border-box;
  padding: 0 8px;                          /* right/left spacing when no pill */
  overflow: hidden;                        /* clip pill corners + any stray overflow */
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* Remove padding from the side that has a pill */
.bt-input-with-label--has-left  { padding-inline-start: 0; }
.bt-input-with-label--has-right { padding-inline-end: 0; }

/* State colours */
.bt-input-with-label--focused  { border-color: var(--color-brand-primary); }
.bt-input-with-label--error    { border-color: var(--text-error); }
.bt-input-with-label--disabled { background: var(--bg-subtle); cursor: not-allowed; }

/* ── Label pill ────────────────────────────────────────────────── */
/* align-self: stretch (inherited from container) fills full height automatically */
.bt-input-with-label__pill {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  padding: 8px;
  background: var(--bg-subtle);
  flex-shrink: 0;
}

/* Outer corners only — inner edge flush with field border */
.bt-input-with-label__pill--left  { border-radius: var(--radius-sm) 0 0 var(--radius-sm); }
.bt-input-with-label__pill--right { border-radius: 0 var(--radius-sm) var(--radius-sm) 0; }

.bt-input-with-label--disabled .bt-input-with-label__pill {
  background: var(--bg-subtler);
}

.bt-input-with-label__pill-text {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  white-space: nowrap;
  user-select: none;
}

.bt-input-with-label--disabled .bt-input-with-label__pill-text {
  color: var(--text-disabled);
}

/* ── Content area ──────────────────────────────────────────────── */
/*
 * CRITICAL: box-sizing must be border-box.
 * Without it, padding-top/bottom when floating adds to the outer height
 * (content-box outer = stretch-height + padding), breaking the 48 px constraint.
 * With border-box, padding is INSIDE the stretch-given height (46 px), so
 * inner = 46 − 8 − 8 = 30 px, and the field stays at exactly 48 px.
 */
.bt-input-with-label__content {
  position: relative;
  flex: 1;
  min-width: 0;
  display: flex;
  align-items: center;
  box-sizing: border-box;                  /* ← mandatory, see note above */
  padding-inline-start: var(--space-xs);
  padding-inline-end: var(--space-xs);
  transition: padding-top  150ms cubic-bezier(0.4, 0, 0.2, 1),
              padding-bottom 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When label is floating — add top/bottom breathing room */
.bt-input-with-label__content--floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

/* ── Floating label ────────────────────────────────────────────── */
.bt-input-with-label__label {
  position: absolute;
  inset-inline-start: var(--space-xs);
  inset-inline-end: var(--space-xs);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-secondary);
  pointer-events: none;
  user-select: none;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: top 150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/*
 * Floating: label at top: 8 px from content area outer edge.
 * Content area padding-top is also 8 px → label sits in the padding zone.
 * Input text is at 8 px (pad) + 16 px (input pad-top) = 24 px from outer. ✓
 */
.bt-input-with-label__label--floating {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-xs);
}

.bt-input-with-label--focused  .bt-input-with-label__label--floating { color: var(--color-brand-primary); }
.bt-input-with-label--error    .bt-input-with-label__label           { color: var(--text-error); }
.bt-input-with-label--disabled .bt-input-with-label__label           { color: var(--text-disabled); }

.bt-input-with-label__label-required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Input field ───────────────────────────────────────────────── */
/*
 * height: 100% fills the content area's inner height.
 *   Resting:  inner = 46 px → input 46 px; browser centres single-line text. ✓
 *   Floating: inner = 30 px → input 30 px; padding-top 16 px → text at 8+16=24 px. ✓
 */
.bt-input-with-label__field {
  flex: 1;
  min-width: 0;
  border: none;
  outline: none;
  background: transparent;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-primary);
  padding: 0;
  height: 100%;
}

.bt-input-with-label__field::placeholder {
  color: var(--text-secondary);
}

.bt-input-with-label--disabled .bt-input-with-label__field {
  cursor: not-allowed;
  color: var(--text-disabled);
}

/* When label is floating: shift input text below the 16 px floating label */
.bt-input-with-label__content--floating .bt-input-with-label__field {
  padding-top: 16px;
}

/* ── Clear (×) button ──────────────────────────────────────────── */
/*
 * Sibling of content area (NOT inside it) so it can use align-self: center
 * and stay vertically centred in the full 46 px field height regardless of
 * whether the label is floating.
 */
.bt-input-with-label__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  align-self: center;                      /* stays centred even when content has padding */
  background: none;
  border: none;
  padding: 0;
  margin-inline-start: var(--space-xs);
  cursor: pointer;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-input-with-label__clear img,
.bt-input-with-label__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Helper / error text ───────────────────────────────────────── */
.bt-input-with-label__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-with-label__helper-text        { flex: 1; color: var(--text-secondary); }
.bt-input-with-label__helper-text--error { color: var(--text-error); }

.bt-input-with-label__counter {
  color: var(--text-secondary);
  flex-shrink: 0;
}

/**
 * Props for {@link BTInputWithLabel}.
 *
 * @example Left label (unit prefix like "kg", "IDR")
 * <BTInputWithLabel left-label="kg" label="Weight" v-model="value" />
 *
 * @example Right label
 * <BTInputWithLabel right-label="m²" label="Area" v-model="value" />
 *
 * @example Both sides
 * <BTInputWithLabel left-label="From" right-label="IDR" label="Amount" v-model="value" />
 */
export interface BTInputWithLabelProps {
  /** Current value (v-model). */
  modelValue?: string;

  /**
   * Text shown inside the left label pill.
   * When omitted no left pill is rendered.
   */
  leftLabel?: string;

  /**
   * Text shown inside the right label pill.
   * When omitted no right pill is rendered.
   */
  rightLabel?: string;

  /**
   * Floating label inside the input — sits centred when empty/idle,
   * floats small (12 px) at the top on focus or when the field has a value.
   */
  label?: string;

  /** Appends " *" (red) to the floating label. @default false */
  required?: boolean;

  /** Hint text shown inside the input when empty and focused. */
  placeholder?: string;

  /** Disables all interaction and dims the field. @default false */
  disabled?: boolean;

  /** Makes the field read-only (shows value, blocks edits). @default false */
  readOnly?: boolean;

  /** Red border + validation text shown below the field. */
  errorText?: string;

  /** Text shown below the field when there is no error. */
  helperText?: string;

  /** HTML id forwarded to the underlying <input>. */
  id?: string;

  /** HTML name forwarded to the underlying <input>. */
  name?: string;

  /** Maximum character count; also used by showCharCount. */
  maxLength?: number;

  /** Show current / max character counter below the field. @default false */
  showCharCount?: boolean;
}

/**
 * positionFloating — shared smart-flip positioning utility.
 *
 * Measures available space around a trigger element and places a floating
 * panel (already rendered in the DOM at position:fixed) below or above
 * depending on which direction has more room. Clamps horizontally so the
 * panel never overflows the viewport edges.
 *
 * Usage:
 *   // After the panel is in the DOM (watch flush:'post' or nextTick):
 *   positionBelow(triggerEl, panelEl, { gap: 4, margin: 8 });
 *
 * Also exported: positionDropdown — same algorithm but centres the panel
 * horizontally over an anchor element (for header pill dropdowns).
 */

export interface PositionOptions {
  /** Gap between trigger edge and panel edge. Default: 4. */
  gap?: number;
  /** Minimum distance from viewport edges. Default: 8. */
  margin?: number;
}

/**
 * Position a panel below or above `trigger`, left-aligned (then clamped).
 * Mutates `panel.style.top / left` and returns the resolved direction.
 */
export function positionBelow(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: PositionOptions = {},
): 'below' | 'above' {
  const { gap = 4, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Vertical: prefer below, flip above when there's not enough space ────────
  const spaceBelow = vh - tRect.bottom - gap;
  const spaceAbove = tRect.top - gap;
  const goAbove    = spaceBelow < pRect.height && spaceAbove >= pRect.height;

  const top = goAbove
    ? tRect.top  - pRect.height - gap
    : tRect.bottom + gap;

  // ── Horizontal: align to trigger left, clamp to viewport ───────────────────
  let left = tRect.left;
  if (left + pRect.width > vw - margin) left = vw - margin - pRect.width;
  if (left < margin)                    left = margin;

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;

  return goAbove ? 'above' : 'below';
}

export type PopoverSide   = 'top' | 'bottom' | 'left' | 'right';
export type PopoverAlign  = 'start' | 'center' | 'end';

/**
 * Position a popover panel relative to a trigger with auto-flip on all axes.
 * Respects the requested `side` but flips to the opposite if there is no room.
 */
export function positionPopover(
  trigger: HTMLElement,
  panel: HTMLElement,
  opts: { side?: PopoverSide; align?: PopoverAlign; sideOffset?: number; margin?: number } = {},
): void {
  const { side = 'bottom', align = 'start', sideOffset = 8, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Resolve side with auto-flip ─────────────────────────────────────────────
  let resolvedSide = side;
  if (side === 'bottom') {
    const fits = vh - tRect.bottom - sideOffset >= pRect.height;
    if (!fits && tRect.top - sideOffset >= pRect.height) resolvedSide = 'top';
  } else if (side === 'top') {
    const fits = tRect.top - sideOffset >= pRect.height;
    if (!fits && vh - tRect.bottom - sideOffset >= pRect.height) resolvedSide = 'bottom';
  } else if (side === 'right') {
    const fits = vw - tRect.right - sideOffset >= pRect.width;
    if (!fits && tRect.left - sideOffset >= pRect.width) resolvedSide = 'left';
  } else /* left */ {
    const fits = tRect.left - sideOffset >= pRect.width;
    if (!fits && vw - tRect.right - sideOffset >= pRect.width) resolvedSide = 'right';
  }

  // ── Main axis ───────────────────────────────────────────────────────────────
  let top  = 0;
  let left = 0;
  if      (resolvedSide === 'bottom') top  = tRect.bottom + sideOffset;
  else if (resolvedSide === 'top')    top  = tRect.top - pRect.height - sideOffset;
  else if (resolvedSide === 'right')  left = tRect.right  + sideOffset;
  else /* left */                     left = tRect.left  - pRect.width - sideOffset;

  // ── Cross axis (alignment) ──────────────────────────────────────────────────
  if (resolvedSide === 'top' || resolvedSide === 'bottom') {
    if      (align === 'start')  left = tRect.left;
    else if (align === 'center') left = tRect.left + tRect.width / 2 - pRect.width / 2;
    else /* end */               left = tRect.right - pRect.width;

    // Clamp horizontally
    left = Math.min(left, vw - margin - pRect.width);
    left = Math.max(left, margin);
  } else {
    if      (align === 'start')  top = tRect.top;
    else if (align === 'center') top = tRect.top + tRect.height / 2 - pRect.height / 2;
    else /* end */               top = tRect.bottom - pRect.height;

    // Clamp vertically
    top = Math.min(top, vh - margin - pRect.height);
    top = Math.max(top, margin);
  }

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;
}

/**
 * Position a small dropdown centred horizontally over `anchor`, below or above.
 * Used by BTCalendarHeader month/year pills.
 */
export function positionCentered(
  anchor: HTMLElement,
  dropdown: HTMLElement,
  opts: PositionOptions = {},
): void {
  const { gap = 4, margin = 8 } = opts;
  const aRect = anchor.getBoundingClientRect();
  const dRect = dropdown.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // Vertical: prefer below, flip above
  const spaceBelow = vh - aRect.bottom - gap;
  const spaceAbove = aRect.top - gap;
  const goAbove    = spaceBelow < dRect.height && spaceAbove >= dRect.height;

  const top = goAbove
    ? aRect.top  - dRect.height - gap
    : aRect.bottom + gap;

  // Horizontal: centre over anchor, clamp
  let left = aRect.left + aRect.width / 2 - dRect.width / 2;
  if (left + dRect.width > vw - margin) left = vw - margin - dRect.width;
  if (left < margin)                    left = margin;

  dropdown.style.top  = `${Math.round(top)}px`;
  dropdown.style.left = `${Math.round(left)}px`;
}
